import{c as a,Q as n,j as t,m as r}from"./chunks/framework.BXc4yaFE.js";const f=JSON.parse('{"title":"Building AI Coding Agents for the Terminal: Scaffolding, Harness, Context Engineering, and Lessons Learned","description":"","frontmatter":{"title":"Building AI Coding Agents for the Terminal: Scaffolding, Harness, Context Engineering, and Lessons Learned","source_tier":"P"},"headers":[],"relativePath":"research/agent-harness/references/2603.05344-building-ai-coding-agents-terminal-arxiv.md","filePath":"research/agent-harness/references/2603.05344-building-ai-coding-agents-terminal-arxiv.md","lastUpdated":1779796674000}'),i={name:"research/agent-harness/references/2603.05344-building-ai-coding-agents-terminal-arxiv.md"};function s(o,e,l,d,g,h){return n(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="building-ai-coding-agents-for-the-terminal-scaffolding-harness-context-engineering-and-lessons-learned" tabindex="-1">Building AI Coding Agents for the Terminal: Scaffolding, Harness, Context Engineering, and Lessons Learned <a class="header-anchor" href="#building-ai-coding-agents-for-the-terminal-scaffolding-harness-context-engineering-and-lessons-learned" aria-label="Permalink to &quot;Building AI Coding Agents for the Terminal: Scaffolding, Harness, Context Engineering, and Lessons Learned&quot;">​</a></h1><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2603.05344" target="_blank" rel="noreferrer">https://arxiv.org/abs/2603.05344</a></li><li><strong>收錄日期</strong>: 2026-05-01</li><li><strong>發表</strong>: 2026-03</li><li><strong>重要性</strong>: Priority A — 首篇系統區分 Scaffolding vs Harness 概念的論文</li></ul><hr><h2 id="核心貢獻" tabindex="-1">核心貢獻 <a class="header-anchor" href="#核心貢獻" aria-label="Permalink to &quot;核心貢獻&quot;">​</a></h2><p>首篇明確區分「Scaffolding（組裝期）」與「Harness（執行期）」的論文，以 OPENDEV（Rust 終端機代理）為案例。</p><h2 id="概念定義" tabindex="-1">概念定義 <a class="header-anchor" href="#概念定義" aria-label="Permalink to &quot;概念定義&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>時機</th><th>職責</th></tr></thead><tbody><tr><td><strong>Scaffolding</strong></td><td>執行前（組裝期）</td><td>系統提示、工具定義、subagent 註冊</td></tr><tr><td><strong>Harness</strong></td><td>執行期（執行迴圈）</td><td>工具分派、context 管理、安全執行、session 持久化</td></tr></tbody></table><h2 id="opendev-架構創新" tabindex="-1">OPENDEV 架構創新 <a class="header-anchor" href="#opendev-架構創新" aria-label="Permalink to &quot;OPENDEV 架構創新&quot;">​</a></h2><ol><li><strong>工作負載專門化的模型路由</strong>: 不同任務類型路由到最適合的模型</li><li><strong>懶惰工具發現（Lazy Tool Discovery）</strong>: 減少不必要的工具載入，保護 context budget</li><li><strong>適應性 Context 壓縮</strong>: 動態調整壓縮策略，非固定閾值</li><li><strong>雙代理架構</strong>: Planning agent + Execution agent 分離</li><li><strong>自動化記憶系統</strong>: 事件驅動的跨 session 記憶持久化</li></ol><h2 id="核心洞見" tabindex="-1">核心洞見 <a class="header-anchor" href="#核心洞見" aria-label="Permalink to &quot;核心洞見&quot;">​</a></h2><ul><li>Scaffolding 是靜態配置，Harness 是動態執行時</li><li>大多數 harness 改進來自<strong>結構層面</strong>（工具、中介軟體、記憶），而非提示詞措辭</li><li>Lazy Tool Discovery 可顯著降低 context 占用，同時提升工具選擇精確度</li></ul><h2 id="對設計的啟示" tabindex="-1">對設計的啟示 <a class="header-anchor" href="#對設計的啟示" aria-label="Permalink to &quot;對設計的啟示&quot;">​</a></h2><ul><li>工具列表不應在 session 開始時全部載入</li><li>Harness 的複雜度應根據任務類型動態調整</li><li>Planning 與 Execution 分離可以提升整體品質</li></ul><h2 id="與本-workspace-的關聯" tabindex="-1">與本 Workspace 的關聯 <a class="header-anchor" href="#與本-workspace-的關聯" aria-label="Permalink to &quot;與本 Workspace 的關聯&quot;">​</a></h2><ul><li><code>defer_loading: true</code> 的工具設計 ≈ Lazy Tool Discovery</li><li>plan-mode-expert + implementer 的分工 ≈ 雙代理架構</li><li><code>.claude/settings.json</code> 的 hooks ≈ 事件驅動記憶系統</li></ul><h2 id="參考連結" tabindex="-1">參考連結 <a class="header-anchor" href="#參考連結" aria-label="Permalink to &quot;參考連結&quot;">​</a></h2><ul><li>arXiv Abstract: <a href="https://arxiv.org/abs/2603.05344" target="_blank" rel="noreferrer">https://arxiv.org/abs/2603.05344</a></li></ul>',17)])])}const u=a(i,[["render",s]]);export{f as __pageData,u as default};
